async function runAll(scenarios) {
  console.log(`\u{1F9EA} Eval harness \u2014 run id: ${RUN_ID}`);
  console.log(`\u{1F4CB} ${scenarios.length} scenarios queued.
`);
  const results = [];
  let passed = 0;
  let failed = 0;
  try {
    for (const scenario of scenarios) {
      const result = await runScenario(scenario);
      results.push(result);
      if (result.passed) {
        passed++;
        console.log(`\u2705 ${scenario.id} \u2014 ${scenario.description}`);
      } else {
        failed++;
        console.log(`\u274C ${scenario.id} \u2014 ${scenario.description}`);
        result.errors.forEach((e) => console.log(`     \xB7 ${e}`));
        console.log(`     \xB7 injected fixture ids: [${result.injectedFixtureIds.join(", ")}]`);
      }
    }
  } finally {
    await cleanup();
  }
  console.log(`
${passed} passed, ${failed} failed (${scenarios.length} total)`);
  return { passed, failed, results };
}

