// src/eval/index.ts
async function main() {
  try {
    const summary = await runAll(SCENARIOS);
    if (summary.failed > 0) {
      process.exit(1);
    }
  } catch (err) {
    console.error("Eval harness crashed:", err);
    process.exit(1);
  } finally {
    await db.close();
  }
}
